!function(){"use strict";const STATIC_PREFIX="CBT_STATIC_PACKAGE_",SUBMIT_QUEUE_KEY="CBT_FINAL_SUBMIT_QUEUE_V1",MAX_RETRY_AGE=7*24*60*60*1e3;
function now(){return Date.now()}
function jsonParse(v,fallback){try{return JSON.parse(v)}catch(e){return fallback}}
function scheduleVersion(s){if(!s)return"1";if("function"==typeof window.getScheduleVersion)try{return window.getScheduleVersion(s)}catch(e){}return String(s.versi_soal||s.version||s.updated_at||s.mulai||1)}
function staticKey(examId,version){return STATIC_PREFIX+examId+"_v"+version}
function publicPackage(pkg){if(!pkg||"object"!=typeof pkg)return pkg;const copy={...pkg};delete copy.keys;return copy}
async function idbSet(key,value){if("function"==typeof window.cbtIdbSet)try{await window.cbtIdbSet(key,value)}catch(e){}}
async function idbGet(key){if("function"==typeof window.cbtIdbGet)try{return await window.cbtIdbGet(key)}catch(e){}return null}
function savePackage(key,pkg){const pub=publicPackage(pkg);try{localStorage.setItem(key,JSON.stringify(pub))}catch(e){console.warn("[StaticPackage] localStorage penuh:",e.message)}idbSet(key,pub);return pub}
async function loadPackage(key){const fromIdb=await idbGet(key);if(fromIdb&&Array.isArray(fromIdb.questions)&&fromIdb.questions.length)return fromIdb;return jsonParse(localStorage.getItem(key),null)}
function normalizeQuestion(q,idx){return{...q,id:String(q.id),_index:null!=q._index?q._index:idx,opsi:Array.isArray(q.opsi)?q.opsi:[],bobot:null!=q.bobot?Number(q.bobot)||1:1}}
async function fetchStaticPackage(examId,token,force,skipTokenCheck){const scheduleRes=await window.fetchSupabase("jadwal_ujian",{id:"eq."+examId});if(!scheduleRes.success||!scheduleRes.data||!scheduleRes.data.length)return{success:!1,message:"Ujian tidak ditemukan"};const schedule=scheduleRes.data[0],version=scheduleVersion(schedule),key=staticKey(examId,version);if(!force){const cached=await loadPackage(key);if(cached&&cached.success&&cached.questions&&cached.questions.length)return cached}if(!skipTokenCheck&&schedule.token&&String(token||"").trim().toUpperCase()!==String(schedule.token).trim().toUpperCase())return{success:!1,message:"Token salah!"};if("function"==typeof window.invokeSupabaseFunction){const edge=await window.invokeSupabaseFunction("get_exam_package",{examId,token,skipTokenCheck:!!skipTokenCheck,version},15e3);if(edge.success&&edge.data&&edge.data.success)return savePackage(key,edge.data)}
const q=await window.fetchSupabase("soal",{bank_id:"eq."+schedule.nama_soal});if(!q.success)return{success:!1,message:"Gagal memuat soal"};const questions=(q.data||[]).sort((a,b)=>Number(a.id)-Number(b.id)).map(normalizeQuestion);const pkg={success:!0,static:!0,cacheKey:key,generatedAt:now(),config:{id_ujian:examId,nama_ujian:schedule.nama,durasi:schedule.durasi,end_ms:schedule.selesai,min_selesai:schedule.min_selesai||0,shuffle_soal:schedule.shuffle_soal,shuffle_opsi:schedule.shuffle_opsi,versi_soal:version,kkm:schedule.kkm||75},questions,tokenHash:schedule.token&&"function"==typeof window.simpleHash?window.simpleHash(String(schedule.token).trim().toUpperCase()):null};pkg.tokenHash&&localStorage.setItem("CBT_TOKEN_HASH_"+examId,pkg.tokenHash);return savePackage(key,pkg)}
async function generateStaticPackages(schedules){const list=Array.isArray(schedules)?schedules:[];const out=[];for(const s of list){if(!s||!s.id)continue;try{out.push(await fetchStaticPackage(s.id,s.token||"",!1,!0))}catch(e){out.push({success:!1,examId:s.id,message:e.message})}}return out}
function readQueue(){return jsonParse(localStorage.getItem(SUBMIT_QUEUE_KEY),[]).filter(x=>x&&x.payload&&now()-(x.createdAt||0)<MAX_RETRY_AGE)}
function writeQueue(items){try{localStorage.setItem(SUBMIT_QUEUE_KEY,JSON.stringify(items))}catch(e){console.warn("[SubmitQueue] gagal menyimpan queue:",e.message)}}
function queueSubmit(payload,error){const id=(payload.examId||payload.id_ujian||"exam")+"_"+((payload.user&&payload.user.id)||payload.userId||"user");const items=readQueue().filter(x=>x.id!==id);items.push({id,payload,attempts:0,createdAt:now(),nextAt:now()+3e4,lastError:String(error||"queued")});writeQueue(items);return{success:!0,queued:!0,message:"Jawaban final disimpan lokal dan akan dikirim ulang otomatis."}}
async function flushSubmitQueue(){if(!navigator.onLine)return{success:!1,offline:!0};let items=readQueue();if(!items.length)return{success:!0,count:0};const keep=[];let sent=0,ts=now();for(const item of items){if(item.nextAt&&item.nextAt>ts){keep.push(item);continue}try{const res=await directSubmit(item.payload);if(res&&res.success){sent++;continue}item.lastError=res&&res.error||res&&res.message||"unknown";item.attempts=(item.attempts||0)+1;item.nextAt=now()+Math.min(9e5,3e4*Math.pow(2,Math.min(item.attempts,5)));keep.push(item)}catch(e){item.lastError=e.message;item.attempts=(item.attempts||0)+1;item.nextAt=now()+Math.min(9e5,3e4*Math.pow(2,Math.min(item.attempts,5)));keep.push(item)}}writeQueue(keep);return{success:!0,sent,pending:keep.length}}
async function directSubmit(payload){if("function"==typeof window.invokeSupabaseFunction){const edge=await window.invokeSupabaseFunction("submit_exam",payload,2e4);if(edge.success&&edge.data&&(edge.data.success||edge.data.alreadySubmitted))return edge.data;return{success:!1,error:edge.error||edge.status||"Edge Function gagal"}}return{success:!1,error:"Edge Function tidak tersedia"}}
function wrapGasRun(){const base=window.gasRun;if("function"!=typeof base||base._staticRuntimeWrapped)return;const wrapped=async function(action,...args){if("getExamData"===action||"getExamDataOptimized"===action)return fetchStaticPackage(args[0],args[1],!!args[2],!!args[3]);if("submitExam"===action){const payload=args[0]||{};try{const res=await directSubmit(payload);if(res&&res.success)return res;const fallback=await base.apply(this,[action,...args]);return fallback&&fallback.success?fallback:queueSubmit(payload,fallback&&fallback.error||fallback&&fallback.message)}catch(e){return queueSubmit(payload,e.message)}}if("getAdminMonitoringData"===action&&"function"==typeof window.invokeSupabaseFunction){const edge=await window.invokeSupabaseFunction("admin_summary",{adminPass:sessionStorage.getItem("admin_pwd")||""},12e3);if(edge.success&&edge.data&&edge.data.success)return edge.data}return base.apply(this,[action,...args])};wrapped._staticRuntimeWrapped=!0;window.gasRun=wrapped;window._supaGasRun=wrapped}
window.CBTStaticRuntime={generateStaticPackages,fetchStaticPackage,flushSubmitQueue,queueSubmit,readSubmitQueue:readQueue};window.addEventListener("online",()=>flushSubmitQueue());setInterval(()=>flushSubmitQueue().catch(()=>{}),3e4);window.addEventListener("supabase-patch-ready",wrapGasRun);setTimeout(wrapGasRun,0);setTimeout(()=>{if(window.State&&Array.isArray(window.State.schedules))generateStaticPackages(window.State.schedules).catch(()=>{})},2500);console.log("[StaticRuntime] Ready")}();
